// V1.0: 格式化同步进度
const rows = $input.all().map(r => r.json);
if (rows.length === 0 || !rows[0].doc_type) {
  return { json: { success: true, syncing: false, progress: [], overall_pct: 0, last_error: null } };
}
let totalBatches = 0, completedBatches = 0, lastError = null, syncing = false;
const progress = rows.map(r => {
  const total = Number(r.total) || 0;
  const completed = Number(r.completed) || 0;
  const running = Number(r.running) || 0;
  const failed = Number(r.failed) || 0;
  const pending = Number(r.pending) || 0;
  totalBatches += total; completedBatches += completed;
  if (running > 0 || pending > 0) syncing = true;
  if (r.last_error) lastError = r.last_error;
  return { doc_type: r.doc_type, total, completed, running, failed, pending, current_month: r.current_month || null };
});
const overallPct = totalBatches > 0 ? Math.round(completedBatches / totalBatches * 100) : 0;
return { json: { success: true, syncing, progress, overall_pct: overallPct, last_error: lastError } };
